<template><h1>Subir archivo a R2</h1><form @submit.prevent='send'><input type='file' ref='f'/><button>Subir</button></form><p>{{msg}}</p></template><script setup>import {ref} from 'vue';const f=ref(null);const msg=ref('');const send=async()=>{ const fd=new FormData(); fd.append('file', f.value.files[0]); const r=await fetch('/upload',{method:'POST',body:fd}); msg.value=await r.text(); };</script>